def lengthOfLIS(nums):
    if not nums:
        return 0

    n = len(nums)
    dp = [1] * n

    for i in range(1, n):
        for j in range(i):
            if nums[j] < nums[i]:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)


# 测试
if __name__ == "__main__":
    print(lengthOfLIS([10,9,2,5,3,7,101,18]))  # 4
    print(lengthOfLIS([0,1,0,3,2,3]))          # 4
    print(lengthOfLIS([7,7,7,7,7,7,7]))       # 1
